class Solution:
    def smallestValue(self, n):
        def prime_sum(x):
            total = 0
            d = 2
            while d * d <= x:
                while x % d == 0:
                    total += d
                    x //= d
                d += 1
            if x > 1:
                total += x
            return total

        seen = set()
        cur = n
        while cur not in seen:
            seen.add(cur)
            nxt = prime_sum(cur)
            if nxt == cur:
                return cur
            cur = nxt

