var smallestValue = function(n) {
    const primeSum = (x) => {
        let total = 0;
        for (let d = 2; d * d <= x; d++) {
            while (x % d === 0) {
                total += d;
                x = Math.floor(x / d);
            }
        }
        if (x > 1) total += x;
        return total;
    };

    while (true) {
        const s = primeSum(n);
        if (s === n) return n;
        n = s;
    }
};
